  const notion = new Client({ auth: process.env.NOTION_API_KEY })
  const DB_ID = process.env.NOTION_DATABASE_ID ?? ''

  export async function getPosts(options = {}) {
    if (!DB_ID) throw new Error('NOTION_DATABASE_ID not set')
    const filter = buildFilter(options)
    const response = await notion.databases.query({ database_id: DB_ID, filter, sorts: [{ property: 'publishedAt', direction: 'descending' }] })
    return response.results.filter(isFullPage).map(parsePage)
  }

  function parsePage(page: PageObjectResponse): Post {
    return {
      id: page.id,
      title: extractTitle(page.properties['title']),
      slug: extractRichText(page.properties['slug']),
      category: extractSelect(page.properties['category']),
      tags: extractMultiSelect(page.properties['tags']),
      publishedAt: extractDate(page.properties['publishedAt']),
      coverImage: extractUrl(page.properties['coverImage']),
      excerpt: extractRichText(page.properties['excerpt']) || undefined,
      status: extractSelect(page.properties['status']) as PostStatus,
    }
  }

